using Financeiro.Domain.Entities; using Microsoft.EntityFrameworkCore; using Microsoft.EntityFrameworkCore.Metadata.Builders;
namespace Financeiro.Infrastructure.Persistence.Configurations; public class DespesaPeriodoConfiguration : IEntityTypeConfiguration<DespesaPeriodo>{ public void Configure(EntityTypeBuilder<DespesaPeriodo> b){ b.ToTable("despesas_periodo"); b.HasKey(x=>x.Id); b.Property(x=>x.PeriodoPagamentoId).HasColumnName("periodo_pagamento_id").IsRequired(); b.Property(x=>x.Descricao).HasColumnName("descricao").HasMaxLength(150).IsRequired(); b.Property(x=>x.Valor).HasColumnName("valor").HasPrecision(18,2).IsRequired(); b.Property(x=>x.Tipo).HasColumnName("tipo").HasMaxLength(50).IsRequired(); b.Property(x=>x.CreatedAt).HasColumnName("created_at").IsRequired(); b.Property(x=>x.UpdatedAt).HasColumnName("updated_at"); } }
